import os, pandas as pd, numpy as np

base = '/home/mrsar/protein-ag/past-published-data/disease-relevant non-inhibited/'

all_fits = []
for root, dirs, files in os.walk(base):
    for f in files:
        if f == 'fit.tsv':
            all_fits.append(os.path.join(root, f))

# Look at the hardest datasets: Alphasyn (seeded, starts high)
# and prp (near-zero x0)
for p in sorted(all_fits):
    rel = p.replace(base, '')
    if 'Alphasyn' in rel:
        df = pd.read_csv(p, sep='\t')
        cols = list(df.columns[1:])
        x0 = df['X'].values
        # Show first 5 and last 3 rows
        print(f'{rel}: x0=[{x0[0]:.3f}..{x0[-1]:.3f}]')
        for col in cols[:2]:
            y = df[col].values
            print(f'  {col[-20:]}: y[0:5]={y[:5].round(4)}, y[-3:]={y[-3:].round(4)}')
""}

